package com.comp2154.student_system.controller;
import com.comp2154.student_system.model.Student; import com.comp2154.student_system.service.StudentService; import jakarta.validation.Valid; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/students")
public class StudentController { private final StudentService service; public StudentController(StudentService service){this.service=service;} @GetMapping public List<Student> getAllStudents(){return service.getAllStudents();} @GetMapping("/{id}") public Student getStudentById(@PathVariable Integer id){return service.getStudentById(id);} @PostMapping public ResponseEntity<Student> createStudent(@Valid @RequestBody Student s){ return ResponseEntity.status(HttpStatus.CREATED).body(service.createStudent(s)); } @PutMapping("/{id}") public Student updateStudent(@PathVariable Integer id,@Valid @RequestBody Student s){ return service.updateStudent(id,s);} @DeleteMapping("/{id}") public Map<String,String> deleteStudent(@PathVariable Integer id){ service.deleteStudent(id); return Map.of("message","Student deleted successfully"); } }
